PUBLIC_BASE = f"{SUPABASE_URL}/storage/v1/object/public/{BUCKET}"
UPLOAD_BASE = f"{SUPABASE_URL}/storage/v1/object/{BUCKET}"

def patch(fname: str) -> str:
    pub_url = f"{PUBLIC_BASE}/{fname}"
    try:
        html = urllib.request.urlopen(pub_url, timeout=15).read().decode("utf-8", errors="replace")
    except Exception as e:
        return f"SKIP (download failed: {e})"

    if OLD_ID not in html:
        return "SKIP (placeholder not found — already patched or different template)"

    patched = html.replace(OLD_ID, NEW_ID)
    data    = patched.encode("utf-8")
    up_url  = f"{UPLOAD_BASE}/{fname}"

    req = urllib.request.Request(
        up_url, data=data, method="PUT",
        headers={
            "Authorization": f"Bearer {ANON_KEY}",
            "Content-Type":  "text/html; charset=utf-8",
            "x-upsert":      "true",
        }
    )
    try:
        urllib.request.urlopen(req, timeout=20)
        return "OK"
    except urllib.error.HTTPError as e:
        return f"FAIL ({e.code}: {e.read().decode()[:100]})"
    except Exception as e:
        return f"FAIL ({e})"


def main():
    total   = len(FILENAMES)
    ok      = 0
    skipped = 0
    failed  = 0

    print(f"Patching GA4 ID in {total} mockups: {OLD_ID} → {NEW_ID}\n")

    for i, fname in enumerate(FILENAMES, 1):
        result = patch(fname)
        status = result.split()[0]
        if status == "OK":
            ok += 1
        elif status == "SKIP":
            skipped += 1
        else:
            failed += 1
        print(f"  [{i:>3}/{total}] {fname[:50]:<50}  {result}")
        # Tiny delay to avoid hammering Supabase
        if i % 10 == 0:
            time.sleep(0.5)

    print(f"\nDone — {ok} patched · {skipped} skipped · {failed} failed")

if __name__ == "__main__":
    main()
